
import axios from 'axios'
import { mapState } from 'vuex'

let titlePage = ''
let backupImage = ''
function isValidHttpUrl (string) {
  let url
  try {
    url = new URL(string)
  } catch (_) {
    return false
  }
  return url.protocol === 'http:' || url.protocol === 'https:'
}
export default {
  name: 'PrevieTemplatePage',
  async asyncData ({ params }) {
    await axios.get(`https://dev-api.unimind.id/v1/creative/${params.detail}`)
      .then((res) => {
        titlePage = res.data.data.name
        if (res.data.data.config.backupImg !== undefined) {
          if (isValidHttpUrl(res.data.data.config.backupImg)) {
            backupImage = res.data.data.config.backupImg
          } else {
            backupImage = 'https://dev-api.unimind.id/v1/obs?fileKey=' + res.data.data.config.backupImg
          }
        } else if (isValidHttpUrl(res.data.data.template.thumbnail)) {
          backupImage = res.data.data.template.thumbnail
        } else {
          backupImage = 'https://dev-api.unimind.id/v1/obs?fileKey=' + res.data.data.template.thumbnail
        }
      }).catch(() => {
      })
  },
  data () {
    return {
      type: '',
      url: '',
      isLoading: true,
      dialogInfo: true,
      fileKey: '',
      height: 0,
      width: 0,
      campaignName: '',
      creativeName: '',
      templateName: '',
      window: {
        width: 0,
        height: 0
      },
      staticSrc: '',
      dataFormDetail: {},
      contentHTML: '',
      format: '',
      handleRole: true,
      templateId: null,
      previewSrc: '',
      previewDevice: [
        // {
        //   id: 2,
        //   name: 'Desktop (1366x768)',
        //   icon: 'dekstop'
        // },
        // {
        //   id: 5,
        //   name: 'iOS (414 x 896)',
        //   icon: 'ios'
        // }
      ],
      selectedPreviewDevice: {
        id: 1,
        name: 'Creative Only',
        icon: 'full_canvas'
      },
      showDevice: false,
      previewTemplate: [
        {
          id: 1,
          name: 'Kompas.com',
          icon: 'kompas'
        }
      ],
      selectedPreviewTemplate: {
        id: 1,
        name: 'Kompas.com',
        icon: 'kompas'
      },
      publisher: null,
      showPreview: false,
      device: null
    }
  },
  head () {
    return {
      title: 'UNIMIND Preview | ' + titlePage,
      meta: [
        {
          hid: 'og:title',
          property: 'og:title',
          content: 'UNIMIND Preview | ' + titlePage
        },
        {
          hid: 'og:description',
          property: 'og:description',
          content: 'Made with UNIMIND. Copyright Ⓒ 2023 Kompas Gramedia'
        },
        {
          hid: 'og:image',
          property: 'og:image',
          content: backupImage
        },
        {
          hid: 'og:thumb',
          property: 'og:thumb',
          content: backupImage
        }
      ]
    }
  },
  layout: 'login',
  auth: false,
  computed: {
    ...mapState({
      dataDetailCreative: (state) => {
        return state.creative.dataDetailCreative
      },
      dataForm: (state) => {
        return state.creative.dataForm
      },
      isLoadingForm: (state) => {
        return state.creative.isLoading
      },
      roleId: (state) => {
        return state.user.roleId
      }
    })
  },
  mounted () {
    // window.addEventListener('resize', this.handleResize)
    // this.handleResize()
    // this.getAll()
    // this.checkRole()
    this.checkParam()
  },
  methods: {
    refresh () {
      this.$nuxt.refresh()
    },
    checkParam () {
      this.isLoading = true
      this.device = this.$router.currentRoute.query.type
      if (this.device === null || this.device === undefined) {
        this.staticSrc = 'https://dev-static.unimind.id/creative_template/custom/scrollFX/preview/kompas-mobile.html'
        this.isLoading = false
      }
      if (this.device === 'scrollfx') {
        this.staticSrc = 'https://dev-static.unimind.id/creative_template/custom/scrollFX/preview/kompas-mobile.html'
        this.isLoading = false
      }
      if (this.device === 'expandable') {
        this.staticSrc = 'https://dev-static.unimind.id/creative_template/custom/kompas-mobile.html'
        this.isLoading = false
      }
    },
    openDevice () {
      this.showDevice = !this.showDevice
      this.showPreview = false
    },
    openPreview () {
      this.showPreview = !this.showPreview
      this.showDevice = false
    },
    toUrl () {
      window.open(this.dataDetailCreative.config.targets[0].url)
    },
    back () {
      this.$router.go(-1)
    },
    btnInfo () {
      this.dialogInfo = !this.dialogInfo
    },
    checkRole () {
      if (this.roleId === 4) {
        this.handleRole = false
      } else {
        this.handleRole = true
      }
    },
    async copyURL () {
      const host = 'https://dev-space.unimind.id/demo?type=' + this.$router.currentRoute.query.type
      try {
        await navigator.clipboard.writeText(host)
        this.$notifier.showMessage({
          content: 'Link copied to clipboard.',
          type: 'success'
        })
      } catch ($e) {
        this.$notifier.showMessage({
          content: 'Cannot copy',
          type: 'failed'
        })
      }
    }
  }
}
